use std::cell::RefCell;
use std::rc::Rc;

struct Counter {
    value: RefCell<i32>,
}

impl Counter {
    fn new(initial_value: i32) -> Self {
        Counter { value: RefCell::new(initial_value) }
    }

    // Method to safely read the current value by borrowing once.
    fn read(&self) -> i32 {
        *self.value.borrow()
    }

    // This method performs a complete Read-Modify-Write cycle using one mutable borrow guard.
    fn increment(&self) {
        println!("\n--- Attempting to mutate value via scope ---");
        {
            // Create a local scope block. The 'guard' variable holds the unique mutable borrow.
            let mut guard = self.value.borrow_mut(); 
            *guard += 1; // Modify the data through the single, exclusive guard.
        }
        // When the inner scope ends, 'guard' is dropped, and the borrow is automatically released.
        println!("Mutation successful: Borrow released.");
    }
}

fn main() {
    // Rc allows multiple owners (shared pointers) to point to the same Counter data structure.
    let counter_a = Rc::new(Counter::new(10));

    println!("Initial Value: {}", counter_a.read());

    // First mutation attempt
    counter_a.increment(); 
    println!("Value after first increment: {}", counter_a.read());

    // Second mutation attempt (demonstrates that the borrow was released)
    counter_a.increment(); 
    println!("Final Value: {}", counter_a.read());
}

use std::cell::RefCell;
use std::rc::Rc;

struct Node {
    name: String,
    value: i32,
}

// We wrap the node in Rc<RefCell<T>> to allow multiple shared pointers 
// and controlled mutation.
type SharedNode = Rc<RefCell<Node>>;

fn main() {
    // 1. Create the initial, shared node instance
    let original_node: SharedNode = Rc::new(RefCell::new(Node {
        name: String::from("Start"),
        value: 10,
    }));

    // 2. Clone pointers to share ownership (Rc handles this)
    let node_a = original_node.clone();
    let node_b = original_node.clone();

    println!("--- Initial State ---\n{:?}", node_a.borrow().value);

    // --- Demonstrate Safe Mutation (Borrowing) ---
    // We can get a mutable borrow from A, which prevents B from mutating simultaneously.
    { 
        let mut borrowed_a = node_a.borrow_mut();
        borrowed_a.value += 5;
        println!("\n--- After A Mutates (Borrowing) ---\n{:?}", original_node.borrow().value);
    }

    // --- Demonstrate Panic on Double Mutation Attempt ---
    /* 
    // If we uncomment this, the program will panic at runtime because 
    // RefCell detects two simultaneous mutable borrows.
    { 
        let _guard1 = node_a.borrow_mut();
        let _guard2 = node_b.borrow_mut(); // <-- This line causes a panic!
    }
    */

    // --- Demonstrate Reading from Multiple Sources ---
    // We can safely read the value multiple times because we only use .borrow() (read-only access).
    let final_value_a = node_a.borrow().value;
    let final_value_b = node_b.borrow().value;

    println!("\n--- Final State ---\nValue read via A: {}", final_value_a);
    println!("Value read via B: {}", final_value_b);
}

