fn main() {
    // 1. Create the initial node, wrapped for shared mutable access.
    let node_a: SharedNode = Rc::new(RefCell::new(Node::new(1, "Initial Data A")));

    println!("--- Initial State ---\n{:?}", node_a.borrow());

    // --- First Mutation (Successful Borrow) ---
    { 
        // We borrow mutably here to change the data.
        let mut borrowed_node = node_a.borrow_mut();
        println!("\n[Scope 1: Mutating] Changing data via mutable borrow...");
        borrowed_node.data = "Data changed by Scope 1!".to_string();
    }
    // The mutable borrow is released when the block ends.

    // --- Second Mutation (Successful Borrow) ---
    { 
        // We can mutate it again because the first borrow was dropped.
        let mut borrowed_node = node_a.borrow_mut();
        println!("[Scope 2: Mutating] Changing data again via second mutable borrow...");
        borrowed_node.data = "Data changed by Scope 2!".to_string();
    }

