use std::cell::RefCell;

struct Node {
    id: u32,
    // The adjacency map needs interior mutability for updates during traversal
    neighbors: RefCell<std::collections::HashMap<u32, u32>>
}

impl Node {
    fn new(id: u32) -> Self {
        Node { id, neighbors: RefCell::new(std::collections::HashMap::new()) }
    }

    // This method simulates updating a neighbor's weight during traversal.
    fn update_neighbor_weight(&self, target_id: u32, new_weight: u32) -> Result<(), String> {
        // We borrow mutably from the RefCell to perform the write operation.
        let mut map = self.neighbors.borrow_mut();
        if map.contains_key(&target_id) {
            map.insert(target_id, new_weight);
            Ok(()) 
        } else {
            Err(format!("Node {} has no edge to target {}", self.id, target_id))
        }
    }
}

fn main() {
    let node_a = Node::new(1);
    let node_b = Node::new(2);

    // Setup initial state: A -> B (weight 10)
    { 
        let mut map_a = node_a.neighbors.borrow_mut();
        map_a.insert(node_b.id, 10);
    }

    println!("--- Initial State Setup Complete ---n");

    // Simulate traversal update: A updates its edge to B
    match node_a.update_neighbor_weight(node_b.id, 50) {
        Ok(_) => println!("Successfully updated weight from {} to 50 on Node A.", node_b.id),
        Err(e) => println!("Error during update: {}", e),
    }

    // Demonstrate that we can read the data safely afterwards
    { 
        let map = node_a.neighbors.borrow();
        println!("Current neighbors on Node A: {:?}", map);
    }
}
